sql:
SELECT field_name
FROM data_fields
WHERE field_description LIKE '%transaction%';

SELECT block_number 
FROM blocks 
WHERE block_id = 0;

SELECT name, description 
FROM blockchains 
WHERE network_type = 'public';

SELECT COUNT(*) 
FROM blockchains
WHERE name = 'Ethereum';

SELECT consensus_algorithm, COUNT(*) as count
FROM blockchains
GROUP BY consensus_algorithm;

SELECT MAX(change_date) 
FROM transaction_versions
WHERE transaction_id = 0;

